files.content:
:host {
  display: block;
  position: relative;
  width: 100%;
  height: 100%;
  min-height: 0;
  box-sizing: border-box;
  -webkit-user-select: none;
  user-select: none;
}

.conversation-list {
  position: relative;
  display: flex;
  flex-direction: column;
  width: 100%;
  height: 100%;
  min-height: 0;
  box-sizing: border-box;
}

.conversation-list__viewport {
  position: relative;
  flex: 1 1 auto;
  min-height: 0;
  overflow: auto;
  box-sizing: border-box;
}

.conversation-list__content {
  position: relative;
  min-height: 100%;
  padding: var(--dimension-space-100);
  padding-bottom: calc(
    var(--dimension-space-100) + var(--ds-scroll-overlay-block-size, 0px)
  );
  box-sizing: border-box;
}

.conversation-list__fade {
  position: absolute;
  right: 0;
  bottom: 0;
  left: 0;
  z-index: 1;
  height: var(--ds-scroll-overlay-fade-block-size, 0);
  pointer-events: none;
  background-color: var(
    --ds-scroll-overlay-surface-color,
    var(--_shell-chrome-bg, var(--color-background-primary))
  );
  --ds-scroll-edge-fade-size: 100%;
}

.conversation-list__fade::before {
  content: '';
  position: absolute;
  inset: 0;
  background-image: var(
    --ds-scroll-overlay-surface-image,
    var(--ds-shell-gradient-image, none)
  );
  background-position: var(--ds-scroll-overlay-surface-position, 0 0);
  background-attachment: fixed;
  background-size: var(
    --ds-scroll-overlay-surface-size,
    var(--ds-shell-gradient-size, auto)
  );
  background-repeat: no-repeat;
  opacity: var(
    --ds-scroll-overlay-surface-image-opacity,
    var(--ds-shell-gradient-opacity, 1)
  );
}

.conversation-list__empty {
  display: contents;
}

.conversation-list__actions {
  position: absolute;
  right: 0;
  bottom: 0;
  z-index: var(--dimension-z-index-floating);
  padding: 0 var(--dimension-space-200) var(--dimension-space-200) 0;
}

.conversation-list__actions--footer {
  left: 0;
  padding: 0 var(--dimension-space-100) var(--dimension-space-100);
}

.conversation-list__actions-surface {
  display: flex;
  border-radius: var(--dimension-radius-half);
  box-shadow: var(--effect-elevation-elevated-md);
}

.conversation-list__actions--footer .conversation-list__actions-surface {
  width: 100%;
}

.conversation-list__actions-surface:empty {
  display: none;
}

import { Component, Element, h, Host, Prop } from '@stencil/core';
import { ScrollOverlayController } from '../../utils/scroll-overlay-controller';

export type ConversationListActionLayout = 'floating' | 'footer';

@Component({
  tag: 'ds-conversation-list',
  styleUrl: 'ConversationList.css',
  styleUrls: ['../../utils/scroll-edge-fade.css'],
  scoped: true,
})
export class ConversationList {
  @Element() el!: HTMLElement;

  /** Corner icon action or full-width persistent footer action. */
  @Prop() actionLayout: ConversationListActionLayout = 'floating';

  private viewport?: HTMLElement;
  private content?: HTMLElement;
  private overlay?: HTMLElement;
  private scrollOverlayController?: ScrollOverlayController;
  private emptySlotObserver?: MutationObserver;

  componentDidLoad(): void {
    if (!this.viewport || !this.content || !this.overlay) return;
    this.scrollOverlayController = new ScrollOverlayController({
      host: this.el,
      viewport: this.viewport,
      content: this.content,
      overlay: this.overlay,
      overlayContentSelector: '[slot="actions"]',
    });
    this.scrollOverlayController.connect();
    this.syncEmptyStateLayout();
    this.emptySlotObserver = new MutationObserver(this.syncEmptyStateLayout);
    this.emptySlotObserver.observe(this.el, { childList: true, subtree: true });
  }

  disconnectedCallback(): void {
    this.scrollOverlayController?.disconnect();
    this.emptySlotObserver?.disconnect();
  }

  private syncEmptyStateLayout = (): void => {
    const emptyState = this.el.querySelector<HTMLElement>('[slot="empty"]');
    if (emptyState) {
      emptyState.style.setProperty('position', 'absolute');
      emptyState.style.setProperty('inset-block-start', '0');
      emptyState.style.setProperty('inset-inline', '0');
      emptyState.style.setProperty(
        'inset-block-end',
        'var(--ds-scroll-overlay-block-size, 0)',
      );
      emptyState.style.setProperty('height', 'auto');
      emptyState.style.setProperty('box-sizing', 'border-box');
    }
    this.scrollOverlayController?.sync();
  };

  render() {
    return (
      <Host>
        <div class="conversation-list">
          <div
            class="conversation-list__viewport"
            ref={element => {
              this.viewport = element;
            }}
            onScroll={() => this.scrollOverlayController?.sync()}
          >
            <div
              class="conversation-list__content"
              ref={element => {
                this.content = element;
              }}
            >
              <slot />
              <div class="conversation-list__empty">
                <slot name="empty" />
              </div>
            </div>
          </div>
          <div
            class="conversation-list__fade scroll-edge-fade scroll-edge-fade--top"
            aria-hidden="true"
          />
          <div
            class={{
              'conversation-list__actions': true,
              'conversation-list__actions--footer': this.actionLayout === 'footer',
            }}
            ref={element => {
              this.overlay = element;
            }}
          >
            <div class="conversation-list__actions-surface">
              <slot name="actions" />
            </div>
          </div>
        </div>
      </Host>
    );
  }
}
